import { apiRequest, buildApiUrl } from "./apiClient";

export interface LoginResponse {
  token: string;
}

export interface MeResponse {
  email: string;
  selectedCourses?: string[];
}

export const authService = {
  async register(email: string, password: string): Promise<{ message: string }> {
    return apiRequest<{ message: string }>(buildApiUrl("/auth/register"), {
      method: "POST",
      body: JSON.stringify({ email, password }),
    });
  },

  async login(email: string, password: string): Promise<LoginResponse> {
    return apiRequest<LoginResponse>(buildApiUrl("/auth/login"), {
      method: "POST",
      body: JSON.stringify({ email, password }),
    });
  },

  async getUserData(token: string): Promise<MeResponse> {
    return apiRequest<MeResponse>(buildApiUrl("/users/me"), {
      method: "GET",
      headers: {
        Authorization: `Bearer ${token}`,
      },
    });
  },
};
